    const face = faces[i];
    buf.push(Math.min(0xFF, Math.floor(face.score * 0xFF)));
    buf.push((face.x >> 8) & 0xFF);
    buf.push(face.x & 0xFF);
    buf.push((face.y >> 8) & 0xFF);
    buf.push(face.y & 0xFF);
